css:
@page {
    size: A4;
    margin: 1cm;
}

body{
    font-family: Arial, sans-serif;
    font-size: 12px;
}

.print-container{
    width:100%;
}

/* Shop Name */

.shop-name{
    text-align:center;
    font-size:22px;
    margin-bottom:10px;
}

/* Urgent Banner */

.urgent-banner{
    background:red;
    color:white;
    text-align:center;
    font-size:18px;
    font-weight:bold;
    padding:6px;
    margin-bottom:10px;
}

/* Section Boxes */

.box{
    border:1px solid #ddd;
    padding:10px;
    margin-bottom:10px;
}

.section-title{
    font-size:14px;
    font-weight:bold;
    border-bottom:1px solid #ccc;
    margin-bottom:6px;
}

/* Parts Table */

.parts-table{
    width:100%;
    border-collapse:collapse;
}

.parts-table th,
.parts-table td{
    border:1px solid #ddd;
    padding:6px;
}

.parts-table th{
    background:#f5f5f5;
}

.total-label{
    text-align:right;
}

/* Final Amount */

.final-amount{
    font-size:22px;
    font-weight:bold;
    text-align:right;
    margin-top:12px;
}

/* QR Code */

.qr-section{
    text-align:right;
    margin-top:20px;
}

/* Page Break */

.page-break{
    page-break-before:always;
}

/* Print Media */

@media print{

.no-print{
display:none;
}

}
